'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { FlightPool } = require('../src/flightPool');
const { ResourceClient } = require('../src/resourceClient');

test('shared work gives each direct pool subscriber its own cancellation outcome', async () => {
  let release;
  const pool = new FlightPool((key, signal) => new Promise((resolve, reject) => {
    release = resolve;
    signal.addEventListener('abort', () => reject(signal.reason || new Error('aborted')), { once: true });
  }));
  const closed = new AbortController();
  const cancelled = pool.load('direct', closed.signal);
  const cancelledCheck = assert.rejects(cancelled);
  const survivor = pool.load('direct');
  await Promise.resolve();
  closed.abort(new Error('closed'));
  release('available');
  await cancelledCheck;
  assert.equal(await survivor, 'available');
});

test('a failed client read is not retained as a result', async () => {
  let calls = 0;
  const client = new ResourceClient(async () => {
    calls += 1;
    if (calls === 1) throw new Error('temporary');
    return 'restored';
  });
  await assert.rejects(client.get('retryable'));
  assert.equal(await client.get('retryable'), 'restored');
  assert.equal(calls, 2);
});
